--
-- Add Schema Binding option to [SCore].[EntityPropertyDependantsV]
--
GO
CREATE OR ALTER VIEW	SCore.EntityPropertyDependantsV
               WITH SCHEMABINDING
AS
SELECT	epd.ID,
		epd.RowStatus,
		epd.RowVersion,
		epd.Guid,
		ep.Guid AS ParentPropertyGuid,
		dep.Name AS PropertyName
FROM	SCore.[EntityPropertyDependants] epd
JOIN	SCore.EntityProperties ep ON (ep.ID = epd.ParentEntityPropertyID)
JOIN	SCore.EntityProperties dep ON (dep.ID = epd.DependantPropertyID)
WHERE	(epd.[RowStatus] NOT IN (0, 254))

GO

IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Add Schema Binding option to [SCore].[EntityPropertiesForValidationV]
--
GO
CREATE OR ALTER VIEW	SCore.EntityPropertiesForValidationV
                WITH SCHEMABINDING
AS
SELECT	ep.Guid,
		ep.Name,
		eh.ObjectName AS Hobt,
		eh.SchemaName AS [Schema],
		N'P' AS TargetType
FROM	Score.[EntityProperties] ep
JOIN	SCore.EntityHobts eh ON ep.EntityHoBTID = eh.ID
WHERE	(ep.[RowStatus] NOT IN (0, 254))
	AND	(eh.RowStatus NOT IN (0, 254))

GO

IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

